import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';

const SCREENSHOT_DIR = 'C:/Users/User/nexus-ai/test-screenshots';
const BASE_URL = 'https://nexus-ai-silk-six.vercel.app';

// Ensure screenshot directory exists
if (!fs.existsSync(SCREENSHOT_DIR)) {
  fs.mkdirSync(SCREENSHOT_DIR, { recursive: true });
}

const results = [];

function addResult(page, status, details, errors) {
  results.push({ page, status, details, networkErrors: errors });
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  const page = await context.newPage();

  // Global network error tracker
  let networkErrors = [];

  page.on('response', (response) => {
    const status = response.status();
    if (status >= 400) {
      networkErrors.push({
        url: response.url(),
        status: status,
        statusText: response.statusText(),
      });
    }
  });

  page.on('console', (msg) => {
    if (msg.type() === 'error') {
      console.log(`  [CONSOLE ERROR] ${msg.text()}`);
    }
  });

  // ========================================
  // STEP 1-3: Login
  // ========================================
  console.log('=== STEP 1: Navigate to /login ===');
  networkErrors = [];
  await page.goto(`${BASE_URL}/login`, { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(3000);

  console.log('=== STEP 2: Fill login form ===');
  // Try to find and fill the email field
  const emailSelector = 'input[type="email"], input[name="email"], input[placeholder*="mail"], input[placeholder*="Mail"]';
  const passwordSelector = 'input[type="password"], input[name="password"]';

  try {
    await page.waitForSelector(emailSelector, { timeout: 10000 });
    await page.fill(emailSelector, 'testuser@nexusai-test.com');
    await page.fill(passwordSelector, 'TestPassword123!');
    console.log('  Login form filled.');

    // Click login button
    const loginBtn = page.locator('button[type="submit"], button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login")').first();
    await loginBtn.click();
    console.log('  Login button clicked.');

    // Wait for redirect to /dashboard
    console.log('=== STEP 3: Waiting for redirect to /dashboard ===');
    await page.waitForURL('**/dashboard**', { timeout: 30000 });
    await page.waitForTimeout(3000);
    console.log(`  Redirected to: ${page.url()}`);
  } catch (err) {
    console.log(`  Login error: ${err.message}`);
  }

  // ========================================
  // STEP 4: /dashboard/settings
  // ========================================
  console.log('\n=== STEP 4: /dashboard/settings ===');
  networkErrors = [];
  try {
    await page.goto(`${BASE_URL}/dashboard/settings`, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(5000);

    const screenshotPath = path.join(SCREENSHOT_DIR, '20-settings-fixed.png');
    await page.screenshot({ path: screenshotPath, fullPage: true });
    console.log(`  Screenshot saved: ${screenshotPath}`);

    // Check for profile form indicators
    const bodyText = await page.textContent('body');
    const hasFullName = bodyText.includes('Full Name') || bodyText.includes('full name') || bodyText.includes('Name');
    const hasEmail = bodyText.includes('Email') || bodyText.includes('email');
    const hasSaveButton = await page.locator('button:has-text("Save"), button:has-text("Update"), button:has-text("Submit")').count() > 0;
    const hasSpinner = await page.locator('.animate-spin, [class*="spinner"], [class*="loading"]').count() > 0;
    const hasInfiniteSpinner = hasSpinner && !hasFullName;

    if (hasFullName && hasEmail && !hasInfiniteSpinner) {
      addResult('/dashboard/settings', 'PASS', 'Profile form visible with name/email fields', networkErrors);
      console.log('  PASS: Profile form is displayed');
    } else if (hasInfiniteSpinner) {
      addResult('/dashboard/settings', 'FAIL', 'Infinite spinner still showing', networkErrors);
      console.log('  FAIL: Infinite spinner detected');
    } else {
      addResult('/dashboard/settings', 'PARTIAL', `Name: ${hasFullName}, Email: ${hasEmail}, Save: ${hasSaveButton}, Spinner: ${hasSpinner}`, networkErrors);
      console.log(`  PARTIAL: Name=${hasFullName}, Email=${hasEmail}, Save=${hasSaveButton}, Spinner=${hasSpinner}`);
    }

    if (networkErrors.length > 0) {
      console.log(`  Network errors: ${JSON.stringify(networkErrors)}`);
    }
  } catch (err) {
    addResult('/dashboard/settings', 'ERROR', err.message, networkErrors);
    console.log(`  ERROR: ${err.message}`);
  }

  // ========================================
  // STEP 5: /dashboard/documents/upload
  // ========================================
  console.log('\n=== STEP 5: /dashboard/documents/upload ===');
  networkErrors = [];
  try {
    await page.goto(`${BASE_URL}/dashboard/documents/upload`, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(5000);

    const screenshotPath = path.join(SCREENSHOT_DIR, '21-upload-fixed.png');
    await page.screenshot({ path: screenshotPath, fullPage: true });
    console.log(`  Screenshot saved: ${screenshotPath}`);

    const bodyText = await page.textContent('body');
    const hasUploadZone = bodyText.includes('upload') || bodyText.includes('Upload') || bodyText.includes('drag') || bodyText.includes('Drag') || bodyText.includes('Drop') || bodyText.includes('drop') || bodyText.includes('file') || bodyText.includes('File');
    const hasOrgError = bodyText.includes('set up your organization') || bodyText.includes('organization first');
    const hasDropzone = await page.locator('[class*="dropzone"], [class*="upload"], input[type="file"]').count() > 0;

    if (hasUploadZone && !hasOrgError) {
      addResult('/dashboard/documents/upload', 'PASS', 'Upload zone visible, no org error', networkErrors);
      console.log('  PASS: Upload zone is displayed');
    } else if (hasOrgError) {
      addResult('/dashboard/documents/upload', 'FAIL', 'Still showing "Please set up your organization first"', networkErrors);
      console.log('  FAIL: Organization error still showing');
    } else {
      addResult('/dashboard/documents/upload', 'PARTIAL', `Upload elements: ${hasUploadZone}, Dropzone: ${hasDropzone}, OrgError: ${hasOrgError}`, networkErrors);
      console.log(`  PARTIAL: Upload=${hasUploadZone}, Dropzone=${hasDropzone}, OrgError=${hasOrgError}`);
    }

    if (networkErrors.length > 0) {
      console.log(`  Network errors: ${JSON.stringify(networkErrors)}`);
    }
  } catch (err) {
    addResult('/dashboard/documents/upload', 'ERROR', err.message, networkErrors);
    console.log(`  ERROR: ${err.message}`);
  }

  // ========================================
  // STEP 6: /dashboard/surveys/create
  // ========================================
  console.log('\n=== STEP 6: /dashboard/surveys/create ===');
  networkErrors = [];
  try {
    await page.goto(`${BASE_URL}/dashboard/surveys/create`, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(5000);

    const screenshotPath = path.join(SCREENSHOT_DIR, '22-create-survey-fixed.png');
    await page.screenshot({ path: screenshotPath, fullPage: true });
    console.log(`  Screenshot saved: ${screenshotPath}`);

    const bodyText = await page.textContent('body');
    const hasSurveyBuilder = bodyText.includes('Survey') || bodyText.includes('survey') || bodyText.includes('Question') || bodyText.includes('question') || bodyText.includes('Create') || bodyText.includes('Title');
    const hasOrgError = bodyText.includes('set up your organization') || bodyText.includes('organization first');
    const hasFormElements = await page.locator('input, textarea, select, [contenteditable]').count() > 0;

    if (hasSurveyBuilder && !hasOrgError) {
      addResult('/dashboard/surveys/create', 'PASS', 'Survey builder visible, no org error', networkErrors);
      console.log('  PASS: Survey builder is displayed');
    } else if (hasOrgError) {
      addResult('/dashboard/surveys/create', 'FAIL', 'Still showing "Please set up your organization first"', networkErrors);
      console.log('  FAIL: Organization error still showing');
    } else {
      addResult('/dashboard/surveys/create', 'PARTIAL', `SurveyBuilder: ${hasSurveyBuilder}, FormElements: ${hasFormElements}, OrgError: ${hasOrgError}`, networkErrors);
      console.log(`  PARTIAL: SurveyBuilder=${hasSurveyBuilder}, FormElements=${hasFormElements}, OrgError=${hasOrgError}`);
    }

    if (networkErrors.length > 0) {
      console.log(`  Network errors: ${JSON.stringify(networkErrors)}`);
    }
  } catch (err) {
    addResult('/dashboard/surveys/create', 'ERROR', err.message, networkErrors);
    console.log(`  ERROR: ${err.message}`);
  }

  // ========================================
  // STEP 7: /dashboard/templates/new
  // ========================================
  console.log('\n=== STEP 7: /dashboard/templates/new ===');
  networkErrors = [];
  try {
    await page.goto(`${BASE_URL}/dashboard/templates/new`, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(5000);

    const screenshotPath = path.join(SCREENSHOT_DIR, '23-templates-new.png');
    await page.screenshot({ path: screenshotPath, fullPage: true });
    console.log(`  Screenshot saved: ${screenshotPath}`);

    const bodyText = await page.textContent('body');
    const hasTemplateEditor = bodyText.includes('Template') || bodyText.includes('template') || bodyText.includes('Create') || bodyText.includes('Name') || bodyText.includes('Title');
    const has404 = bodyText.includes('404') || bodyText.includes('not found') || bodyText.includes('Not Found') || bodyText.includes('page could not be found');
    const hasFormElements = await page.locator('input, textarea, select, [contenteditable]').count() > 0;

    // Check HTTP status
    const response = await page.goto(`${BASE_URL}/dashboard/templates/new`, { waitUntil: 'networkidle', timeout: 30000 });
    const httpStatus = response ? response.status() : 'unknown';
    await page.waitForTimeout(2000);

    // Re-take screenshot after second navigation
    await page.screenshot({ path: path.join(SCREENSHOT_DIR, '23-templates-new.png'), fullPage: true });

    if (has404 || httpStatus === 404) {
      addResult('/dashboard/templates/new', 'FAIL', `404 error (HTTP ${httpStatus})`, networkErrors);
      console.log(`  FAIL: 404 page detected (HTTP ${httpStatus})`);
    } else if (hasTemplateEditor && hasFormElements) {
      addResult('/dashboard/templates/new', 'PASS', `Template editor form visible (HTTP ${httpStatus})`, networkErrors);
      console.log(`  PASS: Template editor is displayed (HTTP ${httpStatus})`);
    } else {
      addResult('/dashboard/templates/new', 'PARTIAL', `TemplateEditor: ${hasTemplateEditor}, FormElements: ${hasFormElements}, 404: ${has404}, HTTP: ${httpStatus}`, networkErrors);
      console.log(`  PARTIAL: TemplateEditor=${hasTemplateEditor}, FormElements=${hasFormElements}, 404=${has404}, HTTP=${httpStatus}`);
    }

    if (networkErrors.length > 0) {
      console.log(`  Network errors: ${JSON.stringify(networkErrors)}`);
    }
  } catch (err) {
    addResult('/dashboard/templates/new', 'ERROR', err.message, networkErrors);
    console.log(`  ERROR: ${err.message}`);
  }

  // ========================================
  // SUMMARY
  // ========================================
  console.log('\n========================================');
  console.log('TEST RESULTS SUMMARY');
  console.log('========================================');
  for (const r of results) {
    console.log(`  [${r.status}] ${r.page} — ${r.details}`);
    if (r.networkErrors && r.networkErrors.length > 0) {
      for (const e of r.networkErrors) {
        console.log(`    Network Error: ${e.status} ${e.url}`);
      }
    }
  }

  // Save results to JSON
  const resultsPath = path.join(SCREENSHOT_DIR, 'fixed-pages-test-results.json');
  fs.writeFileSync(resultsPath, JSON.stringify(results, null, 2));
  console.log(`\nResults saved to: ${resultsPath}`);

  await browser.close();
})();

